package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

class ClonePair11813DifferenceFindingTest {

    private final ClonePair11813 subject = new ClonePair11813();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnSourceGuidedInput() {
        Object[] inputs = new Object[]{"\n", 1};
        InvocationOutcome method1Outcome = capture(values -> subject.method1((String) values[0], ((Integer) values[1]).intValue()), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2((String) values[0], ((Integer) values[1]).intValue()), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "String(Cg==)",
            null,
            "java.lang.Object[][String(Cg==),Integer(1)]",
            "java.lang.Object[][String(Cg==),Integer(1)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "String(fA==)",
            null,
            "java.lang.Object[][String(Cg==),Integer(1)]",
            "java.lang.Object[][String(Cg==),Integer(1)]"
        );
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }
}
